@Test public void handlesMultipleControlCharsInAttributeName() {
        Document doc = Jsoup.parse("<p><a \u0006\u0007=test>Link</a></p>");
        assertEquals("<p><a>Link</a></p>", doc.body().html());
    }

@Test public void handlesBooleanAttributeWithOnlyControlChar() {
        Document doc = Jsoup.parse("<input \u0006 type='text'>");
        assertEquals("<input type=\"text\">", doc.body().html());
    }

@Test public void handlesWhitespaceOnlyAttributeName() {
        String html = "<a   =\"value\">test</a>";
        String clean = Jsoup.clean(html, Whitelist.basic());
        assertEquals("<a rel=\"nofollow\">test</a>", clean);
    }
